function solve(s) {
    const N = s.length;
    if (N === 0) return 0;

    // --- Precomputation ---

    // HZL[k]: Does s[0...k-1] contain '0'? (Prefix check)
    const HZL = new Array(N + 1).fill(false);
    for (let k = 1; k <= N; k++) {
        HZL[k] = HZL[k - 1] || (s[k - 1] === '0');
    }

    // HOR[k]: Does s[k...N-1] contain '0'? (Suffix check)
    const HZR = new Array(N + 1).fill(false);
    for (let k = N - 1; k >= 0; k--) {
        HZR[k] = HZR[k + 1] || (s[k] === '0');
    }

    // HOL[k]: Does s[0...k-1] contain '1'?
    const HOL = new Array(N + 1).fill(false);
    for (let k = 1; k <= N; k++) {
        HOL[k] = HOL[k - 1] || (s[k - 1] === '1');
    }

    // HOR_ONE[k]: Does s[k...N-1] contain '1'?
    const HOR_ONE = new Array(N + 1).fill(false);
    for (let k = N - 1; k >= 0; k--) {
        HOR_ONE[k] = HOR_ONE[k + 1] || (s[k] === '1');
    }

    // --- Core Logic ---

    let maxLen = 0;

    // MinL stores the minimum starting index l for a given prefix sum P_l
    // Key: Sum, Value: Minimum index l
    const minL = new Map();

    let currentSum = 0;
    // P[0] = 0, corresponding to l=0
    minL.set(0, 0); 

    // Iterate k from 1 to N. P_k corresponds to the prefix ending at index k-1.
    for (let k = 1; k <= N; k++) {
        // Update prefix sum P_k
        const value = (s[k - 1] === '1' ? 1 : -1);
        currentSum += value;

        // Case 1: No swap (P_k = P_l => Sum = 0)
        if (minL.has(currentSum)) {
            const l = minL.get(currentSum);
            maxLen = Math.max(maxLen, k - l);
        } else {
            minL.set(currentSum, k);
        }

        // Case 2: One swap required to balance s[l...k-1]

        // Subcase 2a: Current imbalance is D = +2 (c1 = c0 + 2). 
        // We need to swap an internal '1' with an external '0'.
        // Required P_l = P_k - 2.
        const T0 = currentSum - 2;
        if (minL.has(T0)) {
            const l = minL.get(T0);
            // Since T0 = P_k - 2, the substring s[l...k-1] has c1 = c0 + 2. 
            // Length k-l must be at least 2. l < k is guaranteed if T0 != P_k.

            // Check external '0' existence: In s[0...l-1] OR in s[k...N-1].
            if (HZL[l] || HZR[k]) {
                maxLen = Math.max(maxLen, k - l);
            }
        }

        // Subcase 2b: Current imbalance is D = -2 (c0 = c1 + 2). 
        // We need to swap an internal '0' with an external '1'.
        // Required P_l = P_k + 2.
        const T1 = currentSum + 2;
        if (minL.has(T1)) {
            const l = minL.get(T1);

            // Check external '1' existence: In s[0...l-1] OR in s[k...N-1].
            if (HOL[l] || HOR_ONE[k]) {
                maxLen = Math.max(maxLen, k - l);
            }
        }
    }

    return maxLen;
}

