use std::collections::HashMap;

fn solve(s: String) -> i64 {
    let n = s.len();
    if n == 0 {
        return 0;
    }

    // --- Precomputation ---
    // HZL[k]: Does s[0...k-1] contain '0'? (Prefix check for '0')
    let mut hzl = vec![false; n + 1];
    for k in 1..=n {
        hzl[k] = hzl[k - 1] || (s.as_bytes()[k - 1] == b'0');
    }

    // HZR[k]: Does s[k...N-1] contain '0'? (Suffix check for '0')
    let mut hzr = vec![false; n + 1];
    for k in (0..n).rev() {
        hzr[k] = hzr[k + 1] || (s.as_bytes()[k] == b'0');
    }

    // HOL[k]: Does s[0...k-1] contain '1'? (Prefix check for '1')
    let mut hol = vec![false; n + 1];
    for k in 1..=n {
        hol[k] = hol[k - 1] || (s.as_bytes()[k - 1] == b'1');
    }

    // HOR_ONE[k]: Does s[k...N-1] contain '1'? (Suffix check for '1')
    let mut hor_one = vec![false; n + 1];
    for k in (0..n).rev() {
        hor_one[k] = hor_one[k + 1] || (s.as_bytes()[k] == b'1');
    }

    // --- Core Logic ---
    let mut max_len: i64 = 0;

    // minL stores the minimum starting index l for a given prefix sum P_l
    // Key: Sum (i32), Value: Minimum index l (i32)
    let mut min_l: HashMap<i32, i32> = HashMap::new();

    let mut current_sum: i32 = 0;
    // P[0] = 0, corresponding to l=0
    min_l.insert(0, 0); 

    // Iterate k from 1 to N. P_k corresponds to the prefix ending at index k-1.
    for k in 1..=n {
        // Update prefix sum P_k
        let value = if s.as_bytes()[k - 1] == b'1' { 1 } else { -1 };
        current_sum += value;

        // Case 1: No swap (P_k = P_l => Sum = 0)
        if let Some(&l) = min_l.get(&current_sum) {
            max_len = max_len.max((k - l) as i64);
        } 

        // Case 2: One swap required to balance s[l...k-1]

        // Subcase 2a: Current imbalance is D = +2 (c1 = c0 + 2). 
        // Required P_l = P_k - 2.
        let t0 = current_sum - 2;
        if let Some(&l) = min_l.get(&t0) {
            // Check external '0' existence: In s[0...l-1] (HZL[l]) OR in s[k...N-1] (HZR[k]).
            if hzl[l as usize] || hzr[k as usize] {
                max_len = max_len.max((k - l) as i64);
            }
        }

        // Subcase 2b: Current imbalance is D = -2 (c0 = c1 + 2). 
        // Required P_l = P_k + 2.
        let t1 = current_sum + 2;
        if let Some(&l) = min_l.get(&t1) {
            // Check external '1' existence: In s[0...l-1] (HOL[l]) OR in s[k...N-1] (HOR_ONE[k]).
            if hol[l as usize] || hor_one[k as usize] {
                max_len = max_len.max((k - l) as i64);
            }
        }

        // Store the current prefix sum and its earliest index k
        if !min_l.contains_key(&current_sum) {
            min_l.insert(current_sum, k as i32);
        }
    }

    max_len
}

